const topics = ($.input.topics || 'AI, cloud computing, cybersecurity, startups, developer tools').split(',').map(t => t.trim()).filter(Boolean);
const today = new Date();
const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const todayStr = today.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const queries = topics.slice(0, 6).map(topic => ({
  topic,
  query: topic + ' latest news trends developments ' + today.getFullYear()
}));

return { queries, topics, weekAgo, today: todayStr, topicCount: topics.length };

const queries = $.steps.buildQueries.output.queries;
const iterations = $.steps.searchAllTopics.response.iterations || [];
let compiled = '';
let totalArticles = 0;

iterations.forEach((iter, i) => {
  const topic = queries[i] ? queries[i].topic : 'Topic ' + (i + 1);
  const results = (iter.searchTopic && iter.searchTopic.response) ? (iter.searchTopic.response.results || iter.searchTopic.response.data || []) : [];
  compiled += '=== TOPIC: ' + topic.toUpperCase() + ' ===\n';
  results.slice(0, 5).forEach((r, j) => {
    compiled += 'Article ' + (j + 1) + ': ' + (r.title || 'N/A') + '\n';
    compiled += 'URL: ' + (r.url || '') + '\n';
    compiled += 'Content: ' + (r.text || r.content || '').slice(0, 1200) + '\n\n';
    totalArticles++;
  });
  compiled += '\n';
});

return { compiled, totalArticles };

const d = $.steps.compileAllNews.output;
const q = $.steps.buildQueries.output;

let prompt = 'You are a senior tech journalist and newsletter editor. Write a compelling, well-curated tech newsletter for ' + q.today + '.\n\n';
prompt += 'TOPICS COVERED: ' + q.topics.join(', ') + '\n';
prompt += 'TOTAL ARTICLES FOUND: ' + d.totalArticles + '\n\n';
prompt += 'SOURCE ARTICLES:\n' + d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Write a professional newsletter with a catchy subject line\n';
prompt += '- Include a brief editorial intro (2-3 sentences)\n';
prompt += '- For each topic, pick the 2-3 most interesting stories\n';
prompt += '- Write concise, engaging summaries\n';
prompt += '- Add brief "why it matters" analysis for key stories\n';
prompt += '- Include source URLs as references\n';
prompt += '- End with a Quick Bites section for smaller items\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "subjectLine": "newsletter subject line",\n';
prompt += '  "preheader": "email preview text (50 chars)",\n';
prompt += '  "editorialIntro": "opening paragraph",\n';
prompt += '  "sections": [\n';
prompt += '    { "topic": "AI", "stories": [{ "headline": "title", "summary": "2-3 sentences", "whyItMatters": "brief", "url": "source" }] }\n';
prompt += '  ],\n';
prompt += '  "quickBites": ["short item 1", "item 2"],\n';
prompt += '  "closingNote": "brief sign-off"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { subjectLine: 'Weekly Tech Digest', preheader: 'Top tech news', editorialIntro: raw.slice(0, 500), sections: [], quickBites: [], closingNote: '' }; }

const ai = $.steps.parseAI.output;
const today = $.steps.buildQueries.output.today;

let html = '<!DOCTYPE html><html><head><meta charset="UTF-8"><style>';
html += 'body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; margin: 0; padding: 0; background: #f5f5f5; color: #333; }';
html += '.container { max-width: 620px; margin: 20px auto; background: #fff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }';
html += '.header { background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: #fff; padding: 30px; text-align: center; }';
html += '.header h1 { margin: 0; font-size: 24px; }';
html += '.header p { margin: 8px 0 0; opacity: 0.9; font-size: 14px; }';
html += '.content { padding: 24px; }';
html += '.intro { font-size: 15px; line-height: 1.6; color: #555; margin-bottom: 24px; border-left: 3px solid #667eea; padding-left: 16px; }';
html += '.section-title { font-size: 18px; color: #333; margin: 24px 0 12px; padding-bottom: 8px; border-bottom: 2px solid #667eea; }';
html += '.story { margin: 16px 0; padding: 12px; background: #f9f9f9; border-radius: 6px; }';
html += '.story h3 { margin: 0 0 8px; font-size: 15px; }';
html += '.story h3 a { color: #667eea; text-decoration: none; }';
html += '.story p { margin: 4px 0; font-size: 14px; line-height: 1.5; color: #555; }';
html += '.story .why { font-style: italic; color: #764ba2; font-size: 13px; }';
html += '.quick-bites { margin: 24px 0; padding: 16px; background: #f0f0ff; border-radius: 6px; }';
html += '.quick-bites h3 { margin: 0 0 12px; color: #667eea; }';
html += '.quick-bites ul { margin: 0; padding-left: 20px; }';
html += '.quick-bites li { margin: 6px 0; font-size: 14px; line-height: 1.4; }';
html += '.footer { text-align: center; padding: 20px; color: #999; font-size: 12px; border-top: 1px solid #eee; }';
html += '</style></head><body>';
html += '<div class="container">';
html += '<div class="header"><h1>' + ($.input.senderName || 'AI Tech Digest') + '</h1><p>' + today + '</p></div>';
html += '<div class="content">';

if (ai.editorialIntro) {
  html += '<div class="intro">' + ai.editorialIntro + '</div>';
}

if (ai.sections && ai.sections.length > 0) {
  ai.sections.forEach(section => {
    html += '<h2 class="section-title">' + (section.topic || 'News') + '</h2>';
    (section.stories || []).forEach(story => {
      html += '<div class="story">';
      if (story.url) {
        html += '<h3><a href="' + story.url + '">' + (story.headline || 'Story') + '</a></h3>';
      } else {
        html += '<h3>' + (story.headline || 'Story') + '</h3>';
      }
      html += '<p>' + (story.summary || '') + '</p>';
      if (story.whyItMatters) html += '<p class="why">Why it matters: ' + story.whyItMatters + '</p>';
      html += '</div>';
    });
  });
}

if (ai.quickBites && ai.quickBites.length > 0) {
  html += '<div class="quick-bites"><h3>Quick Bites</h3><ul>';
  ai.quickBites.forEach(b => { html += '<li>' + b + '</li>'; });
  html += '</ul></div>';
}

if (ai.closingNote) {
  html += '<p style="font-size: 14px; color: #555; margin-top: 24px;">' + ai.closingNote + '</p>';
}

html += '</div>';
html += '<div class="footer">Curated by AI | Powered by Exa + Claude AI | One CLI</div>';
html += '</div></body></html>';

return { html, subject: ai.subjectLine || 'Weekly Tech Digest - ' + today };
